# ── Optional: httpx async HTTP client (replaces urllib for non-blocking I/O) ──
# Used in: async FastAPI endpoints, channel adapters, A2A protocol.
# Falls back gracefully to urllib.request when not installed.
try:
    import httpx as _httpx          # type: ignore
    _HTTPX = True
except ImportError:
    _httpx = None                   # type: ignore
    _HTTPX = False

# ── REQUIRED: cryptography (AES-256-GCM vault encryption) ────────────────────
# AES-256-GCM is the only supported cipher. XOR stream cipher has been removed.
# Install: pip install cryptography>=42.0
try:
    from cryptography.hazmat.primitives.ciphers.aead import AESGCM  # type: ignore
    _AESGCM = True
except ImportError:
    _AESGCM = False
    import warnings
    warnings.warn(
        "UAIS v19: 'cryptography' package is required for vault encryption. "
        "Install it: pip install cryptography>=42.0  "
        "The vault will operate in memory-only mode until installed.",
        RuntimeWarning, stacklevel=1)

try:
    from pydantic import (
        BaseModel, ConfigDict, Field, SecretStr,
        field_validator, model_validator,
    )
    _PYDANTIC = True
except ImportError:
    # Pydantic is required for all model validation. Without it UAIS runs in
    # degraded mode — all validation silently no-ops which can mask bad config.
    # Install: pip install pydantic>=2.0
    import warnings
    warnings.warn(
        "UAIS v19: 'pydantic' is required. Install: pip install pydantic>=2.0  "
        "Running in degraded mode — all config validation is disabled.",
        RuntimeWarning, stacklevel=1)
    class BaseModel:
        def __init__(self, **kwargs):
            for k, v in kwargs.items(): setattr(self, k, v)
        @classmethod
        def model_validate(cls, obj, **kwargs): return cls(**obj) if isinstance(obj, dict) else obj
        def model_dump(self): return self.__dict__
    SecretStr = str     # type: ignore

    _PYDANTIC = False
    def Field(*a, **k): return k.get('default')  # type: ignore[misc]
    def field_validator(*a, **k): return lambda f: f  # type: ignore[misc]
    def model_validator(*a, **k): return lambda f: f  # type: ignore[misc]
    class ConfigDict:  # type: ignore[misc]
        def __init__(self, **k): pass
try:
    import pytest as _pytest_module  # type: ignore
except ImportError:
    _pytest_module = None  # type: ignore

