import dataclasses as _dc  # noqa: E402 (needed by ABModelRouter before _dc alias set below)

# ══════════════════════════════════════════════════════════════════════════════
# §2a  LITELLM BACKEND  — unified provider shim (100+ providers, v20)
# ══════════════════════════════════════════════════════════════════════════════
# LiteLLM wraps 100+ LLM providers behind a single OpenAI-compatible interface
# with built-in retry, rate limiting, and cost tracking.
#
# Auto-selected when:
#   • UAIS_BACKEND=litellm  is set, OR
#   • `litellm` is installed AND the provider is not a local-first backend
#     (Ollama / vLLM / MLX / llama-cpp remain the preferred T0–T2 path).
#
# ENV:  LITELLM_MODEL=claude-3-5-sonnet   override model within LiteLLM routing
#       LITELLM_API_KEY=...               forwarded as OPENAI_API_KEY if set
#       UAIS_LITELLM_BUDGET_USD=5.0       per-session USD spend guard (0=off)

try:
    import litellm as _litellm_mod  # type: ignore
    _LITELLM = True
except ImportError:
    _litellm_mod = None  # type: ignore
    _LITELLM = False

_LITELLM_MODEL  = os.environ.get("LITELLM_MODEL", "")
_LITELLM_BUDGET = float(os.environ.get("UAIS_LITELLM_BUDGET_USD", "0"))


class _LiteLLMBackend:
    """
    LiteLLM provider shim — exposes the same streaming interface as the
    built-in backend adapters so it can be swapped in via ProviderChain.

    Falls back gracefully to a no-op when litellm is not installed.
    """

    def __init__(self, model: str = "") -> None:
        self._model    = model or _LITELLM_MODEL or "gpt-4o-mini"
        self._ready    = _LITELLM
        self._spend    = 0.0   # cumulative USD tracked by litellm callbacks
        if self._ready and _LITELLM_BUDGET > 0:
            try:
                _litellm_mod.success_callback = []   # clear any existing
                _litellm_mod.set_verbose = False
            except Exception:
                pass

    @property
    def name(self) -> str:
        return f"litellm/{self._model}"

    def chat(self, messages: list[dict], stream: bool = True,
             tools: list | None = None) -> Iterator[str]:
        """Streaming chat via LiteLLM. Yields text chunks."""
        if not self._ready:
            yield "[litellm not installed — run: pip install litellm]"
            return
        kwargs: dict = {"model": self._model, "messages": messages, "stream": stream}
        if tools:
            kwargs["tools"]       = tools
            kwargs["tool_choice"] = "auto"
        if _LITELLM_BUDGET > 0 and self._spend >= _LITELLM_BUDGET:
            yield f"[litellm budget exceeded: ${self._spend:.4f} >= ${_LITELLM_BUDGET}]"
            return
        try:
            response = _litellm_mod.completion(**kwargs)
            if stream:
                for chunk in response:
                    delta = chunk.choices[0].delta
                    if hasattr(delta, "content") and delta.content:
                        yield delta.content
                    # Cost tracking via usage metadata when available
                    if hasattr(chunk, "_hidden_params"):
                        cost = chunk._hidden_params.get("response_cost", 0.0)
                        if cost:
                            self._spend += cost
            else:
                yield response.choices[0].message.content or ""
        except Exception as e:
            yield f"[litellm_error: {e}]"

    def spend(self) -> float:
        """Return cumulative USD spend tracked by LiteLLM callbacks."""
        return self._spend


# ══════════════════════════════════════════════════════════════════════════════
# §2d  CONTEXT BUDGET MANAGER  — unified token allocation (v20)
# ══════════════════════════════════════════════════════════════════════════════
# Coordinates how many tokens each context component receives:
#   system_prompt · skills · memory · conversation_history · tool_results
#
# Prevents quality degradation on T0/T1 devices (4K context) where injected
# context crowds out the actual conversation.
#
# Priority order (highest first): system_prompt > conversation > memory > skills
# When total exceeds budget, lower-priority components are truncated first.
#
# Usage:
#   budget = ContextBudgetManager(context_window=4096)
#   chunks = budget.allocate(
#       system_prompt=sp, skills=sk_text, memory=mem_text,
#       history=msg_list, tool_results=tr_text)

class ContextBudgetManager:
    """
    Token-budget-aware context assembler.

    Allocation ratios are configurable via env (UAIS_CTX_*) and fall back
    to sensible defaults for each hardware tier.

    Approximate token counting: 1 token ≈ 4 chars (conservative estimate).
    Use `tiktoken` when available for precision; fall back to char-counting.
    """

    # Default allocation ratios (must sum ≤ 1.0; remainder goes to history)
    _DEFAULT_RATIOS = {
        "system_prompt": 0.15,
        "skills":        0.15,
        "memory":        0.20,
        "tool_results":  0.10,
        # conversation history gets the rest: 1 - sum(above) = 0.40
    }

    def __init__(self, context_window: int = 4096) -> None:
        self._window = context_window
        self._ratios = {
            "system_prompt": float(os.environ.get("UAIS_CTX_SYSTEM",  "0.15")),
            "skills":        float(os.environ.get("UAIS_CTX_SKILLS",  "0.15")),
            "memory":        float(os.environ.get("UAIS_CTX_MEMORY",  "0.20")),
            "tool_results":  float(os.environ.get("UAIS_CTX_TOOLS",   "0.10")),
        }
        history_ratio = max(0.05, 1.0 - sum(self._ratios.values()))
        self._ratios["history"] = history_ratio

    @staticmethod
    def _count_tokens(text: str) -> int:
        """Accurate token count via §TOKENCOUNT (v24). Falls back to char/4."""
        return count_tokens(text)

    @staticmethod
    def _truncate(text: str, max_tokens: int) -> str:
        """Truncate text to approximately max_tokens, preserving whole words."""
        approx_chars = max_tokens * 4
        if len(text) <= approx_chars:
            return text
        return text[:approx_chars].rsplit(" ", 1)[0] + " …[truncated]"

    def allocate(self, *,
                 system_prompt: str = "",
                 skills:        str = "",
                 memory:        str = "",
                 history:       list[dict] | None = None,
                 tool_results:  str = "") -> dict[str, Any]:
        """
        Allocate the context window across all components.

        Returns a dict with truncated strings/lists ready for prompt assembly:
            {"system_prompt": str, "skills": str, "memory": str,
             "history": list[dict], "tool_results": str, "used_tokens": int}
        """
        budgets = {k: int(self._window * r) for k, r in self._ratios.items()}

        truncated_sp    = self._truncate(system_prompt, budgets["system_prompt"])
        truncated_sk    = self._truncate(skills,        budgets["skills"])
        truncated_mem   = self._truncate(memory,        budgets["memory"])
        truncated_tools = self._truncate(tool_results,  budgets["tool_results"])

        # History: keep most recent messages up to budget, preserving pairs
        hist_budget = budgets["history"]
        hist = list(history or [])
        hist_text = json.dumps(hist)
        while hist and self._count_tokens(hist_text) > hist_budget:
            # Drop oldest message (index 0) unless it's the system message
            if hist[0].get("role") == "system":
                hist.pop(1) if len(hist) > 1 else hist.pop(0)
            else:
                hist.pop(0)
            hist_text = json.dumps(hist)

        used = sum(self._count_tokens(t) for t in [
            truncated_sp, truncated_sk, truncated_mem, truncated_tools, hist_text
        ])

        return {
            "system_prompt": truncated_sp,
            "skills":        truncated_sk,
            "memory":        truncated_mem,
            "history":       hist,
            "tool_results":  truncated_tools,
            "used_tokens":   used,
            "budget":        self._window,
        }

    def summary(self) -> str:
        parts = [f"{k}={int(self._window*r)}" for k, r in self._ratios.items()]
        return f"ContextBudget(window={self._window}, {', '.join(parts)})"


# ══════════════════════════════════════════════════════════════════════════════
# §2b  A/B MODEL ROUTER  — automatic model quality tracking + promotion
# ══════════════════════════════════════════════════════════════════════════════
# Routes requests between two (or more) models, tracks success rates per model,
# and auto-promotes the winner after a configurable trial window.
#
# Usage:
#   router = ABModelRouter(hw, provider_chain, workspace)
#   router.add_candidate("qwen3:14b", weight=0.2)   # 20% of requests
#   result = router.select()                          # returns model tag to use
#   router.record_outcome("qwen3:14b", success=True, score=0.85)
#   router.maybe_promote()                            # promotes if winner clear

class ModelTrialStats:
    """Running statistics for one model in an A/B trial."""
    def __init__(self, model: str, requests: int = 0, successes: int = 0,
                 total_score: float = 0.0, weight: float = 0.5) -> None:
        self.model       = model
        self.requests    = requests
        self.successes   = successes
        self.total_score = total_score
        self.weight      = weight
    def __repr__(self) -> str:
        return (f"ModelTrialStats(model={self.model!r}, requests={self.requests}, "
                f"avg_score={self.avg_score:.3f}, weight={self.weight})")

    @property
    def success_rate(self) -> float:
        return self.successes / max(self.requests, 1)

    @property
    def avg_score(self) -> float:
        return self.total_score / max(self.requests, 1)


class ABModelRouter:
    """
    A/B routing across two models with automatic winner promotion.
    Persists trial statistics to workspace so they survive restarts.
    Promotion threshold: winner needs ≥10% better avg_score AND ≥30 requests.
    """
    MIN_REQUESTS   = int(os.environ.get("UAIS_AB_MIN_REQUESTS", "30"))
    PROMOTE_DELTA  = float(os.environ.get("UAIS_AB_PROMOTE_DELTA", "0.10"))

    def __init__(self, workspace: Path) -> None:
        self._ws     = workspace
        self._stats: dict[str, ModelTrialStats] = {}
        self._lock   = threading.Lock()
        self._load()

    def _stats_path(self) -> Path:
        return self._ws / "logs" / "ab_trial_stats.json"

    def _load(self) -> None:
        p = self._stats_path()
        if p.exists():
            try:
                raw = json.loads(p.read_text(encoding="utf-8"))
                for model, d in raw.items():
                    self._stats[model] = ModelTrialStats(**d)
            except Exception as _e:
                log.debug("ab_router_stats_load_error", extra={"path": str(p), "error": str(_e)[:120]})

    def _save(self) -> None:
        p = self._stats_path()
        p.parent.mkdir(parents=True, exist_ok=True)
        try:
            p.write_text(json.dumps(
                {m: {"model": s.model, "requests": s.requests, "successes": s.successes, "total_score": s.total_score, "weight": s.weight} for m, s in self._stats.items()},
                indent=2), encoding="utf-8")
        except Exception as _e:
            log.debug("ab_router_stats_save_error", extra={"path": str(p), "error": str(_e)[:120]})

    def add_candidate(self, model: str, weight: float = 0.5) -> None:
        with self._lock:
            if model not in self._stats:
                self._stats[model] = ModelTrialStats(model=model, weight=weight)
            else:
                self._stats[model].weight = weight

    def select(self) -> str:
        """Weighted random selection among registered candidates."""
        with self._lock:
            if not self._stats:
                return ""
            models  = list(self._stats.keys())
            weights = [self._stats[m].weight for m in models]
            total   = sum(weights)
            r = secrets.token_bytes(4)
            rnd = (int.from_bytes(r, "big") / (2**32)) * total
            cum = 0.0
            for m, w in zip(models, weights):
                cum += w
                if rnd < cum:
                    return m
            return models[-1]

    def record_outcome(self, model: str, success: bool,
                        score: float = 1.0) -> None:
        with self._lock:
            if model not in self._stats:
                self._stats[model] = ModelTrialStats(model=model)
            s = self._stats[model]
            s.requests   += 1
            s.successes  += 1 if success else 0
            s.total_score += score
            self._save()

    def maybe_promote(self) -> str | None:
        """
        Check if there's a clear winner; if so, promote it to weight=1.0.
        Returns the winning model tag, or None if no promotion yet.
        """
        with self._lock:
            if len(self._stats) < 2:
                return None
            candidates = [s for s in self._stats.values()
                          if s.requests >= self.MIN_REQUESTS]
            if len(candidates) < 2:
                return None
            candidates.sort(key=lambda s: s.avg_score, reverse=True)
            best, rest = candidates[0], candidates[1:]
            if all(best.avg_score - r.avg_score >= self.PROMOTE_DELTA
                   for r in rest):
                # Promote winner
                for m in self._stats:
                    self._stats[m].weight = 1.0 if m == best.model else 0.0
                self._save()
                log.info("ab_router_promoted",
                         extra={"model": best.model,
                                "score": round(best.avg_score, 3),
                                "requests": best.requests})
                return best.model
            return None

    def summary(self) -> str:
        with self._lock:
            parts = []
            for m, s in sorted(self._stats.items()):
                parts.append(
                    f"{m}: n={s.requests} "
                    f"score={s.avg_score:.2f} "
                    f"weight={s.weight:.1f}")
            return " | ".join(parts) if parts else "(no trials)"


# ══════════════════════════════════════════════════════════════════════════════
# §2b-bandit  CONTEXTUAL MULTI-ARMED BANDIT ROUTER  (v20)
# ══════════════════════════════════════════════════════════════════════════════
# Upgrades the ABModelRouter's weighted-random selection to a LinUCB-inspired
# contextual bandit that incorporates task signals:
#   • complexity tier   (from ComplexityRouter: low/medium/high)
#   • latency history   (recent p50 per model)
#   • token cost        (tokens consumed per call)
#   • time-of-day       (hour bucket — heavier models tolerated off-peak)
#   • task success rate (per complexity tier, per model)
#
# The bandit maintains per-arm (model) per-context statistics and selects
# the arm with highest UCB score = mean_reward + exploration_bonus.
#
# Falls back to ABModelRouter.select() when no context is provided or when
# fewer than MIN_CONTEXT_REQUESTS observations exist for the context.
#
# ENV:
#   UAIS_BANDIT_ALPHA=1.0   exploration coefficient (higher = more exploration)
#   UAIS_BANDIT_MIN_N=5     min observations before bandit overrides A/B weight

_BANDIT_ALPHA   = float(os.environ.get("UAIS_BANDIT_ALPHA", "1.0"))
_BANDIT_MIN_N   = int(os.environ.get("UAIS_BANDIT_MIN_N",   "5"))


@_dc.dataclass
class _BanditArm:
    """Per-(model, context_bucket) statistics for the contextual bandit."""
    model:        str
    context_key:  str    # e.g. "complexity:high:hour:14"
    n:            int    = 0
    total_reward: float  = 0.0
    total_latency_ms: float = 0.0
    total_tokens: int   = 0

    @property
    def mean_reward(self) -> float:
        return self.total_reward / max(self.n, 1)

    @property
    def mean_latency_ms(self) -> float:
        return self.total_latency_ms / max(self.n, 1)

    @property
    def ucb(self) -> float:
        import math
        if self.n == 0:
            return float("inf")   # unexplored arm always wins UCB
        return self.mean_reward + _BANDIT_ALPHA * math.sqrt(math.log(self.n + 1) / self.n)


class ContextualBanditRouter:
    """
    LinUCB-lite contextual bandit model router.

    select(context) → model tag
    record(model, context, reward, latency_ms, tokens) → updates arm stats

    context dict keys (all optional):
      complexity: "low"|"medium"|"high"   (from ComplexityRouter)
      latency_sla: float                  (max acceptable latency in ms)
      hour: int                           (0–23, defaults to current hour)
    """

    def __init__(self, workspace: Path,
                 ab_router: ABModelRouter) -> None:
        self._ws       = workspace
        self._ab       = ab_router        # fallback for cold-start
        self._arms:    dict[str, _BanditArm] = {}
        self._lock     = threading.Lock()
        self._path     = workspace / "logs" / "bandit_state.json"
        self._load()

    def _context_key(self, context: dict) -> str:
        import datetime as _dt
        hour        = context.get("hour", _dt.datetime.now().hour)
        complexity  = context.get("complexity", "medium")
        hour_bucket = "peak" if 8 <= int(hour) <= 22 else "offpeak"
        return f"complexity:{complexity}:time:{hour_bucket}"

    def _arm_key(self, model: str, ctx_key: str) -> str:
        return f"{model}::{ctx_key}"

    def _load(self) -> None:
        if self._path.exists():
            try:
                raw = json.loads(self._path.read_text(encoding="utf-8"))
                for k, d in raw.items():
                    self._arms[k] = _BanditArm(**d)
            except Exception as _e:
                log.debug("bandit_load_error", extra={"error": str(_e)[:80]})

    def _save(self) -> None:
        self._path.parent.mkdir(parents=True, exist_ok=True)
        try:
            self._path.write_text(
                json.dumps({k: _dc.asdict(a) for k, a in self._arms.items()},
                           indent=2),
                encoding="utf-8")
        except Exception:
            pass

    def select(self, context: dict | None = None) -> str:
        """
        Select the best model for the given context using UCB.
        Falls back to ABModelRouter when insufficient data exists.
        """
        with self._lock:
            ctx_key  = self._context_key(context or {})
            models   = list(self._ab._stats.keys())
            if not models:
                return ""

            best_model = None
            best_ucb   = -1.0
            cold_start = False

            for model in models:
                ak   = self._arm_key(model, ctx_key)
                arm  = self._arms.get(ak)
                if arm is None or arm.n < _BANDIT_MIN_N:
                    cold_start = True
                    break
                if arm.ucb > best_ucb:
                    best_ucb   = arm.ucb
                    best_model = model

            if cold_start or best_model is None:
                # Not enough data — use A/B router's weighted random
                return self._ab.select()

            log.debug("bandit_select",
                      extra={"model": best_model, "ucb": round(best_ucb, 3),
                             "ctx": ctx_key})
            return best_model

    def record(self, model: str, context: dict,
               reward: float, latency_ms: float = 0.0, tokens: int = 0) -> None:
        """Record an outcome for (model, context) — updates UCB arm stats."""
        with self._lock:
            ctx_key = self._context_key(context)
            ak      = self._arm_key(model, ctx_key)
            if ak not in self._arms:
                self._arms[ak] = _BanditArm(model=model, context_key=ctx_key)
            arm                   = self._arms[ak]
            arm.n                += 1
            arm.total_reward     += reward
            arm.total_latency_ms += latency_ms
            arm.total_tokens     += tokens
            self._save()
        # Mirror into ABModelRouter for promotion logic
        self._ab.record_outcome(model, success=reward >= 0.5, score=reward)

    def summary(self) -> str:
        with self._lock:
            parts = []
            for ak, arm in sorted(self._arms.items()):
                parts.append(f"{ak}: n={arm.n} "
                              f"ucb={arm.ucb:.3f} "
                              f"reward={arm.mean_reward:.2f}")
            return " | ".join(parts) if parts else "(no bandit observations)"


# ══════════════════════════════════════════════════════════════════════════════
# §2c  COST TRACKER  — per-task token spend + budget enforcement
# ══════════════════════════════════════════════════════════════════════════════
# Tracks input and output token counts per task. When a budget is set,
# raises BudgetExceededError when spend crosses the threshold so the
# WorkflowEngine can pause and queue a human decision rather than continuing
# to consume tokens unbounded.
#
# Offline-first: all accounting is local. No external billing API required.
# Costs use configurable per-model price tables (defaults match typical
# local inference where cost is compute-time, approximated as token count).
#
# ENV:  UAIS_COST_BUDGET=50000   max tokens per task (0 = unlimited)
#       UAIS_COST_LOG=1           write per-task spend to workspace/cost_log.jsonl

class BudgetExceededError(RuntimeError):
    """Raised by CostTracker when token spend exceeds the task budget."""
    def __init__(self, spent: int, budget: int) -> None:
        super().__init__(
            f"Task budget exceeded: {spent:,} tokens used of {budget:,} limit. "
            f"Raise UAIS_COST_BUDGET or approve via DecisionQueue.")
        self.spent  = spent
        self.budget = budget


@_dc.dataclass
class TaskCost:
    """Accumulated cost record for a single task run."""
    task_id:      str
    model:        str
    prompt_tok:   int   = 0
    completion_tok: int = 0
    tool_calls:   int   = 0
    started_at:   float = _dc.field(default_factory=time.time)
    finished_at:  float = 0.0

    @property
    def total_tokens(self) -> int:
        return self.prompt_tok + self.completion_tok

    def to_dict(self) -> dict:
        return {
            "task_id":        self.task_id,
            "model":          self.model,
            "prompt_tok":     self.prompt_tok,
            "completion_tok": self.completion_tok,
            "tool_calls":     self.tool_calls,
            "total_tokens":   self.total_tokens,
            "started_at":     self.started_at,
            "finished_at":    self.finished_at,
            "duration_s":     round(self.finished_at - self.started_at, 2)
                              if self.finished_at else None,
        }


class CostTracker:
    """
    Thread-safe token cost accumulator with optional budget enforcement.

    Usage::
        tracker = CostTracker(workspace, budget=50_000)
        tracker.start_task("task-123", model="qwen3:8b")
        tracker.record(prompt_tokens=1024, completion_tokens=256)
        tracker.record_tool_call()
        tracker.finish_task("task-123")

    Budget enforcement::
        try:
            tracker.record(prompt_tokens=10_000, completion_tokens=0)
        except BudgetExceededError as e:
            # pause task and queue decision

    Cost log is written to workspace/cost_log.jsonl — one JSON record per task.
    """

    def __init__(self, workspace: Path,
                 budget: int = 0,
                 log_enabled: bool | None = None) -> None:
        self._ws          = workspace
        self._budget      = budget or _COST_BUDGET
        self._log_path    = workspace / "cost_log.jsonl"
        self._log_enabled = (
            log_enabled if log_enabled is not None
            else os.environ.get("UAIS_COST_LOG", "1") == "1"
        )
        self._current:  dict[str, TaskCost] = {}
        self._lock      = threading.Lock()
        self._totals: dict[str, int] = {}   # task_id → running total

    # ── Lifecycle ─────────────────────────────────────────────────────────────
    def start_task(self, task_id: str, model: str = "") -> TaskCost:
        with self._lock:
            tc = TaskCost(task_id=task_id, model=model)
            self._current[task_id] = tc
            self._totals[task_id]  = 0
            log.debug("cost_task_started",
                      extra={"task_id": task_id, "model": model,
                             "budget": self._budget})
            return tc

    def finish_task(self, task_id: str) -> TaskCost | None:
        with self._lock:
            tc = self._current.pop(task_id, None)
            self._totals.pop(task_id, None)
            if tc:
                tc.finished_at = time.time()
                self._flush(tc)
                log.debug("cost_task_finished",
                          extra=tc.to_dict())
            return tc

    # ── Recording ─────────────────────────────────────────────────────────────
    def record(self, prompt_tokens: int = 0,
               completion_tokens: int = 0,
               task_id: str = "") -> None:
        """
        Record token usage for the active (or specified) task.
        Raises BudgetExceededError if cumulative spend exceeds budget.
        """
        with self._lock:
            # Find the target task
            tc: TaskCost | None = None
            if task_id and task_id in self._current:
                tc = self._current[task_id]
            elif len(self._current) == 1:
                tc = next(iter(self._current.values()))
            if tc is None:
                return  # no active task — silently skip

            tc.prompt_tok      += prompt_tokens
            tc.completion_tok  += completion_tokens
            self._totals[tc.task_id] = tc.total_tokens

            if self._budget > 0 and tc.total_tokens > self._budget:
                log.warning("cost_budget_exceeded",
                            extra={"task_id": tc.task_id,
                                   "spent": tc.total_tokens,
                                   "budget": self._budget})
                raise BudgetExceededError(tc.total_tokens, self._budget)

    def record_tool_call(self, task_id: str = "") -> None:
        """Increment tool call counter for the active task."""
        with self._lock:
            tc: TaskCost | None = None
            if task_id and task_id in self._current:
                tc = self._current[task_id]
            elif len(self._current) == 1:
                tc = next(iter(self._current.values()))
            if tc:
                tc.tool_calls += 1

    # ── Reporting ─────────────────────────────────────────────────────────────
    def current_spend(self, task_id: str = "") -> int:
        """Return current token count for the active (or specified) task."""
        with self._lock:
            if task_id:
                return self._totals.get(task_id, 0)
            if self._totals:
                return sum(self._totals.values())
            return 0

    def budget_remaining(self, task_id: str = "") -> int | None:
        """Return remaining token budget, or None if unlimited."""
        if not self._budget:
            return None
        return max(0, self._budget - self.current_spend(task_id))

    def history(self, n: int = 50) -> list[dict]:
        """Return last n completed task cost records from the log file."""
        if not self._log_path.exists():
            return []
        records = []
        try:
            for line in reversed(self._log_path.read_text(
                    encoding="utf-8").splitlines()):
                try:
                    records.append(json.loads(line))
                    if len(records) >= n:
                        break
                except Exception:
                    continue
        except Exception as _e:
            log.debug("cost_history_read_error", extra={"error": str(_e)[:80]})
        return list(reversed(records))

    def summary(self) -> dict:
        """Aggregate stats across all logged tasks."""
        records = self.history(n=1000)
        if not records:
            return {"tasks": 0, "total_tokens": 0, "avg_tokens": 0,
                    "total_tool_calls": 0}
        total_tok  = sum(r.get("total_tokens", 0) for r in records)
        total_calls = sum(r.get("tool_calls", 0) for r in records)
        return {
            "tasks":             len(records),
            "total_tokens":      total_tok,
            "avg_tokens":        total_tok // len(records) if records else 0,
            "total_tool_calls":  total_calls,
        }

    # ── Internal ──────────────────────────────────────────────────────────────
    def _flush(self, tc: TaskCost) -> None:
        if not self._log_enabled:
            return
        try:
            self._log_path.parent.mkdir(parents=True, exist_ok=True)
            with self._log_path.open("a", encoding="utf-8") as fh:
                fh.write(json.dumps(tc.to_dict()) + "\n")
        except Exception as _e:
            log.debug("cost_flush_error", extra={"error": str(_e)[:80]})


# Module-level singleton — initialised lazily by first Agent instantiation
_cost_tracker: CostTracker | None = None

def get_cost_tracker(workspace: Path | None = None,
                     budget: int = 0) -> CostTracker:
    """Return the module-level CostTracker singleton, creating it if needed."""
    global _cost_tracker
    if _cost_tracker is None:
        ws = workspace or Path.home() / ".uais"
        _cost_tracker = CostTracker(ws, budget=budget)
    return _cost_tracker


# §3  BACKEND ADAPTERS  (uniform streaming interface)
# ══════════════════════════════════════════════════════════════════════════════
# All backends expose:
#   complete(messages, *, model, stream, thinking, budget, tools) → Iterator[str]
#
# Provider chain: primary → fallback_1 → fallback_2 → cloud
# "Thinking tax" mitigation: thinking=True only for planning phase
# (design principle: don't use full reasoning for every subtask)
#
# Qwen3 thinking:   Ollama ≥0.7 → payload["think"] = True
# Qwen3.5 thinking: vLLM/SGLang → extra_body chat_template_kwargs enable_thinking
# Nemotron3-Super:  extra_body reasoning_parser="super_v3"

from typing import Protocol, runtime_checkable
@runtime_checkable
class InferenceProvider(Protocol):
    NAME: str
    def alive(self) -> bool: ...
    def complete(self, messages: list[dict], **kwargs) -> Iterator[str]: ...
    async def acomplete(self, messages: list[dict], **kwargs) -> AsyncIterator[str]: ...

class BackendError(RuntimeError): ...


def _json_post(url: str, payload: dict,
               timeout: int = 180) -> Iterator[bytes]:
    """v23: Uses httpx streaming pool when available; falls back to urllib."""
    if _HTTPX_POOL:
        client = get_sync_client()
        if client:
            try:
                with client.stream("POST", url, json=payload,
                                    timeout=timeout) as resp:
                    resp.raise_for_status()
                    for line in resp.iter_lines():
                        if line:
                            yield (line + "\n").encode()
                return
            except Exception as _he:
                # httpx failed — fall through to urllib
                log.debug("json_post_httpx_fallback", extra={"error": str(_he)[:80]})
    data = json.dumps(payload).encode()
    req  = urllib.request.Request(
        url, data=data,
        headers={"Content-Type": "application/json"},
        method="POST")
    try:
        with urllib.request.urlopen(req, timeout=timeout) as r:
            while chunk := r.readline():
                yield chunk
    except urllib.error.URLError as e:
        raise BackendError(f"POST {url}: {e}") from e


async def _ajson_post(url: str, payload: dict,
                     timeout: int = 180) -> AsyncIterator[bytes]:
    """Async version of _json_post using httpx.AsyncClient."""
    if _HTTPX_POOL:
        client = get_async_client()
        if client:
            try:
                async with client.stream("POST", url, json=payload,
                                         timeout=timeout) as resp:
                    resp.raise_for_status()
                    async for line in resp.aiter_lines():
                        if line:
                            yield (line + "\n").encode()
                return
            except Exception as _he:
                log.debug("ajson_post_error", extra={"error": str(_he)[:80]})

    # Fallback: run sync version in thread
    loop = asyncio.get_running_loop()
    gen = _json_post(url, payload, timeout)
    while True:
        try:
            chunk = await loop.run_in_executor(None, next, gen)
            yield chunk
        except StopIteration:
            break


def _ping(url: str, t: int = 2) -> bool:
    """v23: Uses httpx pool when available for connection reuse."""
    if _HTTPX_POOL:
        try:
            client = get_sync_client()
            if client:
                resp = client.get(url, timeout=t)
                return resp.status_code < 500
        except Exception:
            pass
    try:
        urllib.request.urlopen(url, timeout=t)
        return True
    except Exception:
        return False


# ── Alive-check TTL cache (FIX: was per-token HTTP ping) ─────────────────────
_ALIVE_TTL   = float(os.environ.get("UAIS_ALIVE_TTL", "10"))
_alive_cache: dict[str, tuple[bool, float]] = {}
_alive_lock  = threading.Lock()

def _ping_cached(url: str, t: int = 2,
                  circuit_name: str = "") -> bool:
    """Cached HTTP liveness probe — re-checks at most every UAIS_ALIVE_TTL s.
    v23: Checks circuit breaker state before making the network call.
    If the circuit is OPEN the backend is assumed down (no ping needed)."""
    # Fast path: circuit is open — skip the ping entirely
    if circuit_name:
        try:
            cb = CIRCUIT_BREAKERS.get(circuit_name)
            if not cb.allow():
                return False   # circuit open; treat as down
        except Exception:
            pass
    now = time.monotonic()
    with _alive_lock:
        cached = _alive_cache.get(url)
        if cached and now < cached[1]:
            return cached[0]
    result = _ping(url, t)
    with _alive_lock:
        _alive_cache[url] = (result, now + _ALIVE_TTL)
    return result


# ── Ollama ────────────────────────────────────────────────────────────────────
class OllamaBackend:
    """
    Ollama v0.7+ — primary cross-platform backend.
    /api/chat · SSE streaming · think param · native tool calls.
    Docs: https://github.com/ollama/ollama/blob/main/docs/api.md
    """
    NAME = "ollama"

    def __init__(self, host: str = _OLLAMA_HOST):
        self.host  = host.rstrip("/")
        self._chat = f"{self.host}/api/chat"
        self._tags = f"{self.host}/api/tags"

    def alive(self) -> bool:
        return _ping_cached(self._tags, circuit_name="ollama")

    def list_models(self) -> list[str]:
        try:
            return [m["name"] for m in
                    http_get_json(self._tags, timeout=5).get("models", [])]
        except Exception:
            return []

    def pull(self, tag: str) -> None:
        if not any(tag in t for t in self.list_models()):
            print(f"  {yellow('Pulling')} {tag} …")
            subprocess.run(["ollama", "pull", tag], check=True, timeout=600)

    def complete(self, messages: list[dict], *, model: str,
                 stream: bool = True, thinking: bool = False,
                 budget: int = 1024,
                 tools: list[dict] | None = None) -> Iterator[str]:
        payload: dict[str, Any] = {
            "model": model, "messages": messages, "stream": stream,
            "options": {"num_ctx": 32768,
                        "temperature": 0.6 if thinking else 0.7},
        }
        if thinking:
            payload["think"] = True   # Ollama ≥0.7 native think param
        if tools:
            payload["tools"] = tools
        for raw in _json_post(self._chat, payload):
            line = raw.decode("utf-8", errors="replace").strip()
            if not line:
                continue
            try:
                chunk = json.loads(line)
                # Skip internal <think> tokens surfaced by Ollama 0.7+
                if chunk.get("message", {}).get("role") == "thinking":
                    continue
                if tok := chunk.get("message", {}).get("content", ""):
                    yield tok
                if chunk.get("done"):
                    break
            except json.JSONDecodeError:
                continue

    async def acomplete(self, messages: list[dict], *, model: str,
                        stream: bool = True, thinking: bool = False,
                        budget: int = 1024,
                        tools: list[dict] | None = None) -> AsyncIterator[str]:
        payload: dict[str, Any] = {
            "model": model, "messages": messages, "stream": stream,
            "options": {"num_ctx": 32768,
                        "temperature": 0.6 if thinking else 0.7},
        }
        if thinking:
            payload["think"] = True
        if tools:
            payload["tools"] = tools
        async for raw in _ajson_post(self._chat, payload):
            line = raw.decode("utf-8", errors="replace").strip()
            if not line:
                continue
            try:
                chunk = json.loads(line)
                if chunk.get("message", {}).get("role") == "thinking":
                    continue
                if tok := chunk.get("message", {}).get("content", ""):
                    yield tok
                if chunk.get("done"):
                    break
            except json.JSONDecodeError:
                continue


# ── llama-server (T0 / offline fallback) ──────────────────────────────────────
class LlamaCppBackend:
    """
    Wraps llama-server subprocess. T0 IoT / zero-install fallback.
    Karpathy principle: expose every launch parameter; no hidden defaults.
    """
    NAME = "llamacpp"

    def __init__(self, host: str = "127.0.0.1", port: int = 8081):
        self.host = host; self.port = port
        self.base = f"http://{host}:{port}"
        self._proc: subprocess.Popen | None = None

    def alive(self) -> bool:
        return _ping_cached(f"{self.base}/health")

    def start(self, model_path: str, *, n_gpu: int = 0,
              ctx: int = 4096, threads: int = 4) -> None:
        if self._proc and self._proc.poll() is None:
            return
        exe = shutil.which("llama-server") or shutil.which("llama.cpp")
        if not exe:
            raise BackendError("llama-server not found. "
                               "Build: https://github.com/ggerganov/llama.cpp")
        self._proc = subprocess.Popen(
            [exe, "-m", model_path,
             "--host", self.host, "--port", str(self.port),
             "--ctx-size", str(ctx), "--threads", str(threads),
             "--n-gpu-layers", str(n_gpu), "--mlock"],
            stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        for _ in range(40):
            if self.alive(): return
            time.sleep(0.5)
        # Kill the orphaned process before raising so it does not linger
        try:
            self._proc.kill()
        except Exception as _exc:
            log.debug('llamacpp_kill_failed', extra={'error': str(_exc)})
        self._proc = None
        raise BackendError("llama-server did not start in 20s")

    def complete(self, messages: list[dict], *, model: str = "",
                 stream: bool = True, thinking: bool = False,
                 budget: int = 1024,
                 tools: list[dict] | None = None) -> Iterator[str]:
        prompt = "\n".join(f"<|{m['role']}|>\n{m.get('content', '')}" for m in messages)
        for raw in _json_post(f"{self.base}/completion",
                              {"prompt": prompt, "n_predict": 2048,
                               "temperature": 0.6 if thinking else 0.7,
                               "stream": stream}):
            line = raw.decode("utf-8", errors="replace").strip()
            if line.startswith("data: "):
                try:
                    chunk = json.loads(line[6:])
                    if tok := chunk.get("content", ""):
                        yield tok
                    if chunk.get("stop"):
                        break
                except json.JSONDecodeError:
                    continue


# ── OpenAI-compat (vLLM, SGLang, TGI, OpenRouter, cloud) ──────────────────────
class OpenAICompatBackend:
    """
    Uniform adapter for any OpenAI /v1/chat/completions endpoint.
    vLLM ≥0.7 + PagedAttention recommended for T3.
    SGLang ≥0.4 recommended for multi-agent parallel tool calls.
    Nemotron 3 Super: reasoning_parser="super_v3" via extra_body.
    """
    NAME = "openai_compat"

    def __init__(self, base: str = _VLLM_HOST, api_key: str = "EMPTY"):
        self.base    = base.rstrip("/")
        self.api_key = SecretStr(api_key) if _PYDANTIC else api_key  # type: ignore

    def alive(self) -> bool:
        # vLLM exposes /health; SGLang/TGI/OpenRouter may only expose /v1/models
        return _ping(f"{self.base}/health") or _ping(f"{self.base}/v1/models")

    def complete(self, messages: list[dict], *, model: str,
                 stream: bool = True, thinking: bool = False,
                 budget: int = 1024,
                 tools: list[dict] | None = None) -> Iterator[str]:
        payload: dict[str, Any] = {
            "model": model, "messages": messages,
            "stream": stream, "max_tokens": 4096,
            "temperature": 0.6 if thinking else 0.7,
        }
        if thinking:
            # Qwen3.5 via vLLM/SGLang — does NOT support /think soft-switch
            payload["extra_body"] = {
                "chat_template_kwargs": {"enable_thinking": True},
                "thinking_budget": budget,
            }
        if "nemotron" in model.lower():
            payload.setdefault("extra_body", {})
            payload["extra_body"]["reasoning_parser"] = "super_v3"
        if tools:
            payload["tools"] = tools

        headers: dict[str, str] = {
            "Content-Type": "application/json",
            "Authorization": f"Bearer {self.api_key.get_secret_value() if hasattr(self.api_key, 'get_secret_value') else self.api_key}",
        }

        # Anthropic prompt caching: inject cache_control on the system message.
        # Reduces cost by 60–90% on long sessions (cache hit = 0.1× input price).
        # Only applied when talking directly to api.anthropic.com.
        if "anthropic.com" in self.base:
            headers["anthropic-beta"] = "prompt-caching-2024-07-31"
            # Mark the first system message as cacheable
            for msg in payload["messages"]:
                if msg.get("role") == "system":
                    content = msg.get("content", "")
                    if isinstance(content, str):
                        msg["content"] = [
                            {"type": "text", "text": content,
                             "cache_control": {"type": "ephemeral"}}
                        ]
                    elif isinstance(content, list) and content:
                        content[-1]["cache_control"] = {"type": "ephemeral"}
                    break

        data = json.dumps(payload).encode()
        req  = urllib.request.Request(
            f"{self.base}/v1/chat/completions", data=data,
            headers=headers, method="POST")
        try:
            with urllib.request.urlopen(req, timeout=180) as resp:
                for raw in resp:
                    line = raw.decode("utf-8", errors="replace").strip()
                    if not line or line == "data: [DONE]":
                        continue
                    if line.startswith("data: "):
                        try:
                            tok = (json.loads(line[6:])["choices"][0]
                                   .get("delta", {}).get("content", ""))
                            if tok:
                                yield tok
                        except (json.JSONDecodeError, KeyError, IndexError):
                            continue
        except urllib.error.URLError as e:
            raise BackendError(str(e)) from e

    async def acomplete(self, messages: list[dict], *, model: str,
                        stream: bool = True, thinking: bool = False,
                        budget: int = 1024,
                        tools: list[dict] | None = None) -> AsyncIterator[str]:
        payload: dict[str, Any] = {
            "model": model, "messages": messages,
            "stream": stream, "max_tokens": 4096,
            "temperature": 0.6 if thinking else 0.7,
        }
        if thinking:
            payload["extra_body"] = {
                "chat_template_kwargs": {"enable_thinking": True},
                "thinking_budget": budget,
            }
        if "nemotron" in model.lower():
            payload.setdefault("extra_body", {})
            payload["extra_body"]["reasoning_parser"] = "super_v3"
        if tools:
            payload["tools"] = tools

        headers: dict[str, str] = {
            "Content-Type": "application/json",
            "Authorization": f"Bearer {self.api_key.get_secret_value() if hasattr(self.api_key, 'get_secret_value') else self.api_key}",
        }

        if "anthropic.com" in self.base:
            headers["anthropic-beta"] = "prompt-caching-2024-07-31"
            for msg in payload["messages"]:
                if msg.get("role") == "system":
                    content = msg.get("content", "")
                    if isinstance(content, str):
                        msg["content"] = [
                            {"type": "text", "text": content,
                             "cache_control": {"type": "ephemeral"}}
                        ]
                    elif isinstance(content, list) and content:
                        content[-1]["cache_control"] = {"type": "ephemeral"}
                    break

        url = f"{self.base}/v1/chat/completions"
        async for raw in _ajson_post(url, payload):
            line = raw.decode("utf-8", errors="replace").strip()
            if not line or line == "data: [DONE]":
                continue
            if line.startswith("data: "):
                try:
                    tok = (json.loads(line[6:])["choices"][0]
                            .get("delta", {}).get("content", ""))
                    if tok:
                        yield tok
                except (json.JSONDecodeError, KeyError, IndexError):
                    continue


# ── MLX (Apple Silicon) ────────────────────────────────────────────────────────
class MLXBackend(OpenAICompatBackend):
    """
    mlx_lm.server subprocess wrapper.
    4–10× faster than Ollama on M-series due to unified memory architecture.
    """
    NAME = "mlx"

    def __init__(self, host: str = "127.0.0.1", port: int = 8082):
        super().__init__(base=f"http://{host}:{port}", api_key="mlx")
        self._port_n = port
        self._proc: subprocess.Popen | None = None

    def start(self, model_hf: str) -> None:
        if self._proc and self._proc.poll() is None:
            return
        self._proc = subprocess.Popen(
            [sys.executable, "-m", "mlx_lm.server",
             "--model", model_hf,
             "--host", "127.0.0.1", "--port", str(self._port_n)],
            stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
        for _ in range(40):
            if self.alive(): return
            time.sleep(0.5)
        raise BackendError("mlx_lm.server did not start in 20s")


# ── llama-cpp-python in-process backend (T0 — no external binary required) ───────
class LlamaCppPythonBackend:
    """
    Runs llama_cpp.Llama directly inside the UAIS process.
    T0 path: Raspberry Pi, Pi-class SBC 2W, any CPU-only device.
    n_gpu_layers=-1 offloads everything when a GPU is present.
    """
    NAME = "llamacpp_python"

    def __init__(self, model_path: str, n_gpu_layers: int = 0,
                 n_ctx: int = 4096):
        self.model_path   = model_path
        self.n_gpu_layers = n_gpu_layers
        self.n_ctx        = n_ctx
        self._llama       = None

    def _load(self):
        if self._llama is not None:
            return
        try:
            from llama_cpp import Llama  # type: ignore
            self._llama = Llama(
                model_path=self.model_path,
                n_gpu_layers=self.n_gpu_layers,
                n_ctx=self.n_ctx,
                verbose=False,
            )
        except ImportError:
            raise BackendError(
                "llama-cpp-python not installed. "
                "Run: pip install llama-cpp-python")

    def alive(self) -> bool:
        return bool(self.model_path and Path(self.model_path).exists())

    def complete(self, messages: list[dict], *, model: str = "",
                 stream: bool = True, thinking: bool = False,
                 budget: int = 1024,
                 tools: list[dict] | None = None) -> Iterator[str]:
        self._load()
        prompt = "\n".join(f"<|{m['role']}|>\n{m.get('content','')}" for m in messages)
        output = self._llama(prompt, max_tokens=2048,
                             temperature=0.6 if thinking else 0.7,
                             stream=True)
        for chunk in output:
            tok = chunk["choices"][0].get("text", "")
            if tok:
                yield tok

class OnnxBackend:
    """
    ONNX Runtime inference — ultra-light, no native CUDA deps.
    Suitable for Alpine Linux, Pi-class SBC 2W with Python 3.9+.
    Model must be exported to ONNX format (Optimum library).
    """
    NAME = "onnx"

    def __init__(self, model_path: str):
        self.model_path = model_path
        self._pipeline  = None

    def alive(self) -> bool:
        return bool(self.model_path and Path(self.model_path).exists())

    def _load(self):
        if self._pipeline is not None:
            return
        try:
            from optimum.onnxruntime import ORTModelForCausalLM  # type: ignore
            from transformers import AutoTokenizer, pipeline      # type: ignore
            model = ORTModelForCausalLM.from_pretrained(
                self.model_path, provider="CPUExecutionProvider")
            tok = AutoTokenizer.from_pretrained(self.model_path)
            self._pipeline = pipeline("text-generation", model=model,
                                      tokenizer=tok)
        except ImportError:
            raise BackendError(
                "optimum[onnxruntime] not installed. "
                "Run: pip install optimum[onnxruntime]")

    def complete(self, messages: list[dict], *, model: str = "",
                 stream: bool = True, thinking: bool = False,
                 budget: int = 1024,
                 tools: list[dict] | None = None) -> Iterator[str]:
        self._load()
        prompt = "\n".join(f"<|{m['role']}|>\n{m.get('content', '')}" for m in messages)
        result = self._pipeline(prompt, max_new_tokens=512,
                                do_sample=True, temperature=0.7)
        text = result[0]["generated_text"][len(prompt):]
        yield text


# ── SGLang backend (T3 — speculative decode for Qwen3-MoE) ───────────────────────
class SGLangBackend(OpenAICompatBackend):
    """
    SGLang ≥0.4 speculative decode is meaningfully faster for Qwen3-MoE
    workloads vs vLLM at T3.  Uses the same OpenAI-compat /v1/chat/completions.
    """
    NAME = "sglang"

    def __init__(self, host: str = "127.0.0.1", port: int = 30000):
        super().__init__(base=f"http://{host}:{port}", api_key="EMPTY")

    def alive(self) -> bool:
        return _ping_cached(f"{self.base}/health")


# ── LiteLLM cloud gateway (100+ providers through one interface) ─────────────────
class LiteLLMBackend:
    """
    When litellm is installed, replaces bare OpenAICompatBackend(cloud_url).
    Gives automatic retry, cost tracking, model fallback across:
    Anthropic, Gemini, Bedrock, Azure, Groq, Together, and 90+ more.
    """
    NAME = "litellm"

    def __init__(self, model: str = "", api_key: str = ""):
        self._model   = model or os.environ.get("UAIS_LITELLM_MODEL", "gpt-4o")
        self._api_key = SecretStr(api_key) if (api_key and _PYDANTIC) else api_key  # type: ignore

    def alive(self) -> bool:
        try:
            import litellm  # type: ignore  # noqa: F401
            # Only consider alive if a cloud model or API key is configured
            has_key = bool(
                os.environ.get("OPENAI_API_KEY") or
                os.environ.get("ANTHROPIC_API_KEY") or
                os.environ.get("GEMINI_API_KEY") or
                os.environ.get("GROQ_API_KEY") or
                os.environ.get("UAIS_LITELLM_MODEL")
            )
            return has_key
        except ImportError:
            return False

    def complete(self, messages: list[dict], *, model: str = "",
                 stream: bool = True, thinking: bool = False,
                 budget: int = 1024,
                 tools: list[dict] | None = None) -> Iterator[str]:
        try:
            import litellm  # type: ignore
        except ImportError:
            raise BackendError("litellm not installed. Run: pip install litellm")
        chosen = model or self._model
        kwargs: dict[str, Any] = dict(
            model=chosen, messages=messages, stream=True,
            max_tokens=4096, temperature=0.6 if thinking else 0.7,
        )
        if tools:
            kwargs["tools"] = tools
        response = litellm.completion(**kwargs)
        for chunk in response:
            tok = (chunk.choices[0].delta.content or "")
            if tok:
                yield tok


# ── Provider chain ──────────────────────────────────────────────────────────────
class ProviderChain:
    """
    primary → fallback_1 → fallback_2 → cloud.
    Per-agent override via AGENTS.md [provider] directive.
    First alive backend wins — transparent to the caller.
    """
    def __init__(self, providers: list):
        self.providers = providers

    @property
    def active(self) -> InferenceProvider:
        """Return the first alive provider.
        Return first provider as fallback if none are alive — callers get a
        descriptive error from the provider itself rather than a crash here.
        """
        for p in self.providers:
            try:
                if p.alive():
                    return p
            except Exception:
                pass
        # Return first provider as fallback (its complete() will error descriptively)
        if self.providers:
            log.warning("provider_chain_all_dead",
                        extra={"providers": [p.NAME for p in self.providers]})
            return self.providers[0]
        raise BackendError(
            "ProviderChain: empty — run: python uais.py install && python uais.py up")

    def alive(self) -> bool:
        return any(p.alive() for p in self.providers)

    def complete(self, *a, **kw) -> Iterator[str]:
        """True streaming with jittered backoff fallback across providers.
        Yields tokens as they arrive — no full materialisation."""
        import random as _rnd
        errors: list[str] = []
        for provider in self.providers:
            if not provider.alive():
                continue
            # v22: Circuit breaker per provider
            _pname = getattr(provider, "NAME", type(provider).__name__)
            _cb    = CIRCUIT_BREAKERS.get(_pname)
            if not _cb.allow():
                log.debug("circuit_open_skip", extra={"provider": _pname})
                continue
            for attempt in range(2):
                try:
                    # v27: Wrap in OTEL span for distributed tracing
                    _model = kw.get("model", "") or (a[1] if len(a) > 1 else "")
                    with span_llm(_model or _pname):
                        def _safe(_g=provider.complete(*a, **kw)):
                            try:
                                yield from _g
                            except BackendError:
                                raise
                            except Exception as _e:
                                raise BackendError(str(_e)) from _e
                        yield from _safe()
                    _cb.record_success()
                    return
                except BackendError as exc:
                    _cb.record_failure()
                    errors.append(f"{_pname}[{attempt}]: {exc}")
                    log.warning("backend_retry", extra={
                        "provider": _pname,
                        "attempt": attempt, "error": str(exc)})
                    if attempt == 0:
                        time.sleep(2.0 + _rnd.uniform(0, 1.0))
        raise BackendError("All providers failed.\n" + "\n".join(f"  {e}" for e in errors))

    async def acomplete(self, *a, **kw) -> AsyncIterator[str]:
        """Async version of complete(). Yields tokens asynchronously."""
        import random as _rnd
        errors: list[str] = []
        for provider in self.providers:
            # alive() is still sync for now as it's cached/fast
            if not provider.alive():
                continue
            _pname = getattr(provider, "NAME", type(provider).__name__)
            _cb    = CIRCUIT_BREAKERS.get(_pname)
            if not _cb.allow():
                continue

            # Check if provider has acomplete, else fall back to thread
            _acomplete = getattr(provider, "acomplete", None)

            for attempt in range(2):
                try:
                    _model = kw.get("model", "") or (a[1] if len(a) > 1 else "")
                    with span_llm(_model or _pname):
                        if _acomplete:
                            async for tok in _acomplete(*a, **kw):
                                yield tok
                        else:
                            # Fallback: run sync generator in thread
                            loop = asyncio.get_running_loop()
                            gen = provider.complete(*a, **kw)
                            while True:
                                try:
                                    tok = await loop.run_in_executor(None, next, gen)
                                    yield tok
                                except StopIteration:
                                    break
                                except Exception as _e:
                                    raise BackendError(str(_e)) from _e
                    _cb.record_success()
                    return
                except BackendError as exc:
                    _cb.record_failure()
                    errors.append(f"{_pname}[{attempt}]: {exc}")
                    if attempt == 0:
                        await asyncio.sleep(2.0 + _rnd.uniform(0, 1.0))
        raise BackendError("All providers failed.\n" + "\n".join(f"  {e}" for e in errors))




# ══════════════════════════════════════════════════════════════════════════════
# §3b  PROVIDER REGISTRY  (plug-and-play backend extension point)
# ══════════════════════════════════════════════════════════════════════════════
# Register new inference backends at runtime — no source edits required.
#
#   from uais import PROVIDER_REGISTRY, OpenAICompatBackend
#   PROVIDER_REGISTRY.register("my_llm",
#       lambda: OpenAICompatBackend("http://my-server:8080", api_key="secret"))
#
#   # Or via env var:  UAIS_EXTRA_PROVIDERS=myapi=http://host:port?key=KEY

class ProviderRegistry:
    """
    Plug-and-play backend registry.

    Supports three registration patterns:

    1. **Runtime factory** (code):
         PROVIDER_REGISTRY.register("my_llm", lambda: MyBackend(...))

    2. **Env-var string** (UAIS_EXTRA_PROVIDERS):
         Parsed by build_provider_chain(); creates OpenAICompatBackend instances.

    3. **Role-aware delegation** (master/slave topology):
         build_provider_chain() automatically adds RemoteProviders when
         UAIS_ROLE=master and peer slave URLs are discovered.
    """
    def __init__(self) -> None:
        self._factories: dict[str, Callable[[], Any]] = {}
        self._runtime_providers: list[Any] = []

    def register(self, name: str, factory: Callable[[], Any]) -> None:
        """Register a named provider factory.  Called at import time or lazily."""
        self._factories[name] = factory
        instance = factory()
        self._runtime_providers.append(instance)
        log.debug("provider_registered", extra={"name": name})

    def clear(self) -> None:
        """Remove all runtime-registered providers (useful in tests)."""
        self._factories.clear()
        self._runtime_providers.clear()

    def names(self) -> list[str]:
        return list(self._factories.keys())


PROVIDER_REGISTRY = ProviderRegistry()


def build_provider_chain(hw: HardwareProfile) -> ProviderChain:
    providers = []
    # T3: check SGLang first (faster speculative decode for MoE), then vLLM
    if hw.backend == "vllm" or hw.tier >= 3:
        sg = SGLangBackend()
        if sg.alive(): providers.append(sg)
        vb = OpenAICompatBackend(_VLLM_HOST)
        if vb.alive(): providers.append(vb)
    if hw.backend == "mlx" and hw.has_metal:
        mb = MLXBackend()
        if mb.alive(): providers.append(mb)
    if shutil.which("ollama"):
        ob = OllamaBackend()
        providers.append(ob)   # Ollama added even if not yet alive
    if shutil.which("llama-server"):
        providers.append(LlamaCppBackend())
    # In-process llama-cpp-python (T0 — no external binary required)
    _lcpp_model = os.environ.get("UAIS_GGUF_PATH", "")
    if _lcpp_model and Path(_lcpp_model).exists():
        providers.append(LlamaCppPythonBackend(
            _lcpp_model,
            n_gpu_layers=-1 if hw.has_cuda or hw.has_metal else 0))
    # LiteLLM cloud gateway when installed (100+ providers, auto-retry)
    ll = LiteLLMBackend()
    if ll.alive():
        providers.append(ll)
    # Bare OpenAI-compat cloud fallback
    elif cloud_url := os.environ.get("UAIS_CLOUD_URL", ""):
        providers.append(OpenAICompatBackend(
            cloud_url, os.environ.get("UAIS_CLOUD_KEY", "sk-")))
    # Extra providers registered via UAIS_EXTRA_PROVIDERS env var:
    #   name1=http://host:port[?key=MYKEY],name2=http://host2:port2
    if _EXTRA_PROVIDERS_RAW:
        for entry in _EXTRA_PROVIDERS_RAW.split(","):
            entry = entry.strip()
            if "=" not in entry:
                continue
            _ename, _eurl = entry.split("=", 1)
            _ekey = "sk-"
            if "?key=" in _eurl:
                _eurl, _ekey = _eurl.split("?key=", 1)
            providers.append(OpenAICompatBackend(_eurl.strip(), _ekey.strip()))
    # Providers registered at runtime via PROVIDER_REGISTRY
    for p in PROVIDER_REGISTRY._runtime_providers:
        providers.append(p)
    if not providers:
        raise BackendError("No backend binary found.\n  Run: python uais.py install")
    return ProviderChain(providers)


# ══════════════════════════════════════════════════════════════════════════════
# §4  SECURITY SANDBOX
# ══════════════════════════════════════════════════════════════════════════════
# UAIS's #1 security vulnerability (per Cisco AI Security 2025 report):
# no deterministic circuit-breaker on shell tool calls. Malicious skill hub
# skills performed data exfiltration without user awareness.
#
# CriticGate category: "Permission Violation" — we pre-empt it here.
# Two layers: (1) pattern blocklist, (2) workspace path guard.
# Prompt injection detection in tool inputs (prevents "ignore previous").

_BLOCKLIST = [
    r"rm\s+-[rRf]+\s+/",        r"mkfs\.",          r"dd\s+if=",
    r"shred\s+",                  r":\(\)\{.*?\}\s*;", # fork bomb
    r"cat\s+~?/?\.ssh/",         r"cat\s+.*\.pem\b",
    r"env\s*\|",                  r"printenv\b",
    r"curl\s+[^|]+\|\s*(?:ba)?sh", r"wget\s+[^|]+\|\s*(?:ba)?sh",
    r"nc\s+-[el]",                r"python\d?\s+-c\s+.*socket",
    r"sudo\s+",                   r"su\s+-\s",
    r"chmod\s+[0-7]*7[0-7]*",    r"chown\s+root",
    r"base64\s+--decode",         r"eval\s+\$\(",
    r"export\s+.*(?:KEY|TOKEN|SECRET|PASSWORD)",
    # /tmp staging: block executing scripts staged in /tmp
    r"(?:ba)?sh\s+/tmp/",         r"python\d?\s+/tmp/",
    r"perl\s+/tmp/",              r"ruby\s+/tmp/",
    r"curl\s+-[oO]\s+/tmp/",     r"wget\s+-[oO]\s+/tmp/",
]
_BLOCK_RE    = [re.compile(p, re.I | re.S) for p in _BLOCKLIST]

# Prompt injection phrases in tool args
_INJECTION_RE = re.compile(
    r"(ignore\s+(all\s+)?previous|disregard\s+instructions|"
    r"new\s+instructions|you\s+are\s+now|forget\s+(all\s+)?previous|"
    r"\[INST\]|<\|im_start\|>|<\|system\|>)",
    re.I)

# PII / secrets patterns for SemanticGuard
_PII_RE = re.compile(
    r"(\b\d{3}-\d{2}-\d{4}\b"           # SSN
    r"|\b(?:sk|pk)-[A-Za-z0-9]{20,}\b"  # API keys
    r"|AKIA[0-9A-Z]{16}"                 # AWS keys
    r"|-----BEGIN (?:RSA |EC )?PRIVATE KEY)",
    re.I)


_SECRET_MASK_RE = re.compile(
    r'((?:sk|pk)-[A-Za-z0-9]{8})[A-Za-z0-9]+|'
    r'(AKIA[A-Z0-9]{4})[A-Z0-9]+|'
    r'(ghp_[A-Za-z0-9]{4})[A-Za-z0-9]+|'
    r'(Bearer\s+\S{8})\S*|'
    r'(bot\d+:)[A-Za-z0-9_-]+',
    re.I
)

def _mask_secrets(text: str) -> str:
    """Replace recognisable secrets with masked versions for safe logging."""
    return _SECRET_MASK_RE.sub(lambda m: (m.group(0)[:len(m.group(0))//2] + "***"), text)


def semantic_guard(content: str) -> str | None:
    """
    SemanticGuard: scan tool results before injecting into LLM context.
    Returns sanitized summary string if suspicious content is found,
    or None if content is clean (caller uses original in that case).

    Catches: embedded prompt injection, PII (SSN, API keys), and
    common jailbreak delimiters that could hijack the agent context window.
    """
    if _INJECTION_RE.search(content):
        return ("[SEMANTIC_GUARD: prompt injection pattern detected in tool "
                "result — content replaced for safety]")
    if _PII_RE.search(content):
        return ("[SEMANTIC_GUARD: sensitive data (PII/credentials) detected in "
                "tool result — content redacted]")
    return None


def sandbox_check(cmd: str, workspace: Path,
                  allow_outside: bool = False) -> str | None:
    """Return error string if blocked, None if safe."""
    # Prompt injection in the command itself
    if _INJECTION_RE.search(cmd):
        return "[BLOCKED: prompt injection attempt detected in command]"
    # Dangerous pattern blocklist
    for pat in _BLOCK_RE:
        if pat.search(cmd):
            return f"[BLOCKED: dangerous pattern '{pat.pattern[:40]}']"
    # Workspace path guard
    if not allow_outside:
        for token in re.findall(r'[/~][^\s"\']+', cmd):
            resolved = token.replace("~", str(Path.home()))
            if resolved.startswith("/") and \
               not resolved.startswith(str(workspace)) and \
               not any(resolved.startswith(safe)
                       for safe in ("/tmp", *(["/proc/cpuinfo", "/proc/meminfo", "/proc/loadavg", "/proc/uptime"] if platform.system() == "Linux" else []), "/sys/class",
                                    "/usr/bin", "/usr/local/bin")):
                return f"[BLOCKED: path outside workspace — {token}]"
    return None


# ══════════════════════════════════════════════════════════════════════════════
# §4b  CONTAINER SANDBOX  — OS-level isolation for shell tool execution
# ══════════════════════════════════════════════════════════════════════════════
# When UAIS_CONTAINER=1 is set, shell tool calls are routed through a
# fresh ephemeral container (Docker / Podman / nerdctl) instead of running
# directly in the host process.
#
# This provides OS-level enforcement that application-level blocklists cannot:
#   • Filesystem isolation  — container sees only a bind-mounted /workspace copy
#   • Network isolation     — --network=none by default; opt-in with UAIS_CONTAINER_NET=1
#   • PID/user namespace    — runs as UID 65534 (nobody) inside the container
#   • CPU/memory limits     — 1 CPU, 512 MB RAM by default (UAIS_CONTAINER_MEM/CPU)
#   • Automatic cleanup     — --rm ensures the container never persists
#
# Container-sandbox design: when the container runtime is available, the
# application-level sandbox_check() is still applied first as a fast pre-filter,
# then the surviving command is handed to the container for OS-enforced execution.
#
# Env vars:
#   UAIS_CONTAINER=1                 Enable container routing (on by default)
#   UAIS_CONTAINER_RUNTIME=docker    docker | podman | nerdctl  (auto-detected)
#   UAIS_CONTAINER_IMAGE=python:3.12 Base image  (default: python:3.12-slim)
#   UAIS_CONTAINER_NET=0             0=no network (default), 1=bridge
#   UAIS_CONTAINER_MEM=512m          Memory limit (default: 512m)
#   UAIS_CONTAINER_CPU=1             CPU count limit (default: 1)
#   UAIS_CONTAINER_TIMEOUT=30        Hard wall-clock timeout in seconds

_CONTAINER_ENABLED = os.environ.get("UAIS_CONTAINER", "1") == "1"
if os.environ.get("UAIS_CONTAINER") == "0":
    log.warning("container_sandbox_disabled",
                extra={"detail": "UAIS_CONTAINER=0 set — shell tools running without OS-level isolation!"})
_CONTAINER_RUNTIME = os.environ.get("UAIS_CONTAINER_RUNTIME", "")   # auto-detected if blank
_CONTAINER_IMAGE   = os.environ.get("UAIS_CONTAINER_IMAGE", "python:3.12-slim")
_CONTAINER_NET     = "bridge" if os.environ.get("UAIS_CONTAINER_NET", "0") == "1" else "none"
_CONTAINER_MEM     = os.environ.get("UAIS_CONTAINER_MEM", "512m")
_CONTAINER_CPU     = os.environ.get("UAIS_CONTAINER_CPU", "1")
_CONTAINER_TIMEOUT = int(os.environ.get("UAIS_CONTAINER_TIMEOUT", "30"))


def _detect_container_runtime() -> str | None:
    """Return the first available container runtime binary, or None."""
    for rt in (_CONTAINER_RUNTIME,) if _CONTAINER_RUNTIME else ("docker", "podman", "nerdctl"):
        if rt and shutil.which(rt):
            return rt
    return None


class _EphemeralContainerSandbox:
    """
    OS-level container sandbox for shell tool execution (ephemeral one-shot).

    Usage (called automatically by _tool_shell when UAIS_CONTAINER=1):
        cs = _EphemeralContainerSandbox(workspace)
        result = cs.run("ls -la /workspace")

    The workspace directory is bind-mounted read-only at /workspace inside
    the container; a writable /tmp is provided via tmpfs.  The container is
    always removed after execution (--rm).

    Direct usage for testing:
        cs = _EphemeralContainerSandbox(Path("/my/workspace"))
        ok, output = cs.available(), cs.run("echo hello")
    """

    def __init__(self, workspace: Path) -> None:
        self._ws      = workspace
        self._runtime = _detect_container_runtime()

    def available(self) -> bool:
        """True when a container runtime is found and UAIS_CONTAINER=1."""
        return _CONTAINER_ENABLED and self._runtime is not None

    def run(self, cmd: str, timeout: int | None = None) -> str:
        """
        Execute cmd inside an ephemeral container.
        Returns combined stdout+stderr as a string.
        Raises RuntimeError if the runtime is not available.
        """
        if not self._runtime:
            raise RuntimeError(
                "_EphemeralContainerSandbox: no container runtime found "
                "(install docker/podman/nerdctl and set UAIS_CONTAINER=1)")

        wall = timeout or _CONTAINER_TIMEOUT

        # Build the container command
        docker_cmd = [
            self._runtime, "run", "--rm",
            "--network", _CONTAINER_NET,
            "--memory", _CONTAINER_MEM,
            "--cpus",   _CONTAINER_CPU,
            "--user",   "65534:65534",        # nobody:nobody
            "--read-only",                     # immutable root fs
            "--tmpfs",  "/tmp:rw,noexec,size=64m",
            "--volume", f"{self._ws}:/workspace:ro",
            "--workdir", "/workspace",
            "--security-opt", "no-new-privileges",
            "--cap-drop", "ALL",
            _CONTAINER_IMAGE,
            "/bin/sh", "-c", cmd,
        ]

        try:
            proc = subprocess.run(
                docker_cmd,
                capture_output=True, text=True,
                timeout=wall,
            )
            out = (proc.stdout or "") + (proc.stderr or "")
            if proc.returncode != 0:
                out += f"\n[container exit code {proc.returncode}]"
            return out.strip()
        except subprocess.TimeoutExpired:
            return f"[CONTAINER TIMEOUT: command exceeded {wall}s wall time]"
        except FileNotFoundError:
            return f"[CONTAINER ERROR: runtime '{self._runtime}' not found in PATH]"
        except Exception as e:
            return f"[CONTAINER ERROR: {e}]"

    def status(self) -> str:
        """Human-readable availability string for `uais doctor`."""
        if not _CONTAINER_ENABLED:
            return "container sandbox disabled (set UAIS_CONTAINER=1 to enable)"
        if not self._runtime:
            return "UAIS_CONTAINER=1 but no runtime found (install docker/podman/nerdctl)"
        return f"container sandbox ready: {self._runtime} → {_CONTAINER_IMAGE}"


# Module-level singleton; initialised lazily on first tool-shell call.
_container_sandbox: _EphemeralContainerSandbox | None = None


def get_container_sandbox(workspace: Path) -> _EphemeralContainerSandbox:
    """Return the module-level ContainerSandbox singleton."""
    global _container_sandbox
    if _container_sandbox is None:
        _container_sandbox = _EphemeralContainerSandbox(workspace)
    return _container_sandbox


