# §5r  TOOL_REGISTRY BOOTSTRAP  — wire all builtin tool schemas + handlers
# ══════════════════════════════════════════════════════════════════════════════
# This runs once at module load time.  The Agent reads TOOL_REGISTRY.get_tools()
# instead of the raw BUILTIN_TOOLS list so that dynamically registered tools
# are automatically included in every LLM tool-call payload.
#
# NOTE: handlers that need workspace/memory/hw context are registered as
# closures inside Agent.__init__ via TOOL_REGISTRY.register() so they capture
# the right scope.  The stubs below register the *schemas* now; handlers for
# context-sensitive tools are upserted at Agent construction time.

def _bootstrap_tool_registry() -> None:
    """Pre-register all builtin tool schemas into TOOL_REGISTRY.
    Handlers for stateless tools are wired here.
    Context-sensitive tool handlers (need ws/hw/mem) are registered per-Agent
    instance via Agent._register_tool_handlers()."""
    for schema in BUILTIN_TOOLS:
        name = schema["function"]["name"]
        # Register schema now; handler placeholder — Agent overwrites per instance
        if not TOOL_REGISTRY.get_handler(name):
            TOOL_REGISTRY._schemas.append(schema)

_bootstrap_tool_registry()

# Register use_skill tool (v20 — skill composition with cycle detection)
TOOL_REGISTRY.register(_USE_SKILL_SCHEMA, _tool_use_skill)
log.debug("use_skill_registered")

# Register MCP memory tools (v18) — enabled when team_id set or UAIS_MCP_MEMORY=1
if _TEAM_ID != "local" or os.environ.get("UAIS_MCP_MEMORY", "0") == "1":
    register_mcp_memory_tools(TOOL_REGISTRY)
    log.debug("mcp_memory_auto_registered", extra={"team_id": _TEAM_ID})


# ══════════════════════════════════════════════════════════════════════════════
# §5r-ext2  MCP CLIENT  — consume external MCP servers at startup
# ══════════════════════════════════════════════════════════════════════════════
# Set UAIS_MCP_SERVERS=name=http://host:port,gh=http://localhost:3001 to
# auto-discover and register tools from any MCP-compliant server into the
# TOOL_REGISTRY.  Tools appear prefixed: <server_name>__<tool_name>.
#
# Stdio-based MCP servers are not supported here (use the FastAPI gateway).
# Failures are logged at DEBUG level and skipped — startup is never blocked.

def _bootstrap_mcp_clients() -> None:
    """Discover and register tools from external MCP servers (HTTP transport)."""
    raw = os.environ.get("UAIS_MCP_SERVERS", "")
    if not raw:
        return
    _log = logging.getLogger("uais")
    for entry in raw.split(","):
        entry = entry.strip()
        if "=" not in entry:
            continue
        srv_name, url = entry.split("=", 1)
        srv_name = srv_name.strip()
        url      = url.strip().rstrip("/")
        try:
            # Prefer POST initialize → tools/list (MCP JSON-RPC 2.0)
            rpc_payload = json.dumps({
                "jsonrpc": "2.0", "id": 1, "method": "tools/list", "params": {}
            }).encode()
            req = urllib.request.Request(
                f"{url}/mcp",
                data=rpc_payload,
                headers={"Content-Type": "application/json"},
                method="POST",
            )
            resp = json.loads(urllib.request.urlopen(req, timeout=4).read())
            tools = resp.get("result", {}).get("tools", [])
            for tool in tools:
                tname = tool.get("name", "")
                if not tname:
                    continue
                schema = {
                    "type": "function",
                    "function": {
                        "name": f"{srv_name}__{tname}",
                        "description": (
                            f"[{srv_name}] {tool.get('description', '')}"),
                        "parameters": tool.get("inputSchema",
                                      {"type": "object", "properties": {}}),
                    },
                }
                # Capture loop vars in closure
                def _make_handler(base_url: str, tool_name: str):
                    def _handler(args: dict) -> str:
                        call = json.dumps({
                            "jsonrpc": "2.0", "id": 1,
                            "method": "tools/call",
                            "params": {"name": tool_name, "arguments": args},
                        }).encode()
                        r = urllib.request.Request(
                            f"{base_url}/mcp", data=call,
                            headers={"Content-Type": "application/json"},
                            method="POST",
                        )
                        result = json.loads(
                            urllib.request.urlopen(r, timeout=15).read())
                        content = result.get("result", {}).get("content", [{}])
                        return content[0].get("text", str(result)) if content else str(result)
                    return _handler
                TOOL_REGISTRY.register(schema, _make_handler(url, tname))
            if tools:
                _log.info("mcp_client_registered",
                          extra={"server": srv_name, "tools": len(tools)})
        except Exception as exc:
            _log.debug("mcp_client_bootstrap_skip",
                       extra={"server": srv_name, "error": str(exc)[:120]})

_bootstrap_mcp_clients()


# SkillRunner reads that list and spawns the skill in a fresh subprocess with
# only those tool functions wired in. All others raise PermissionError.
# On Linux, wraps with seccomp; on macOS, uses sandbox-exec when available.

class SkillRunner:
    """
    Isolated skill execution: reads 'tools:' from SKILL.md YAML header,
    grants only those capabilities, runs in subprocess.
    """
    _TOOL_WHITELIST = {
        "shell", "read_file", "write_file", "python_exec",
        "web_search", "heartbeat_add", "analyze_image", "build_skill",
        "read_skill", "skill_write",
    }

    @staticmethod
    def _parse_capabilities(skill_md: str) -> list[str]:
        """Extract tools list from SKILL.md YAML front-matter."""
        in_front = False
        for line in skill_md.splitlines():
            if line.strip() == "---":
                in_front = not in_front
                continue
            if in_front and line.strip().startswith("tools:"):
                raw = line.split(":", 1)[1].strip().strip("[]")
                return [t.strip() for t in raw.split(",") if t.strip()]
        return list(SkillRunner._TOOL_WHITELIST)

    @staticmethod
    def run(skill_md: str, task: str, workspace: Path,
            provider: Any, model: str) -> str:
        """Execute skill instructions in an isolated subprocess.

        The subprocess deserialises the payload, constructs a minimal Agent
        with only the declared capability tools wired in, runs the task via
        agent.run_task(), and prints the JSON result to stdout.  All other
        tool names raise PermissionError inside the subprocess so capability
        containment is enforced at the Python level.
        """
        caps    = SkillRunner._parse_capabilities(skill_md)
        # Filter caps against the declared whitelist
        allowed = [c for c in caps if c in SkillRunner._TOOL_WHITELIST]
        payload = json.dumps({
            "skill_md":          skill_md,
            "task":              task,
            "workspace":         str(workspace),
            "model":             model,
            "allowed_tool_names": allowed,
            "ollama_host":       os.environ.get("OLLAMA_HOST",
                                                "http://127.0.0.1:11434"),
        })
        # The runner script is injected via -c and receives the JSON payload
        # as sys.argv[1].  It imports uais from the same directory so the
        # full tool set is available; only the allowed subset is wired in.
        runner_code = textwrap.dedent("""
            import sys, json, os
            from pathlib import Path

            d    = json.loads(sys.argv[1])
            ws   = Path(d["workspace"])
            caps = set(d["allowed_tool_names"])

            # Locate uais.py (parent of workspace, or same dir as this process)
            _uais_candidates = [
                ws.parent / "uais.py",
                Path(sys.argv[0]).parent / "uais.py",
                Path(__file__).parent / "uais.py" if "__file__" in dir() else None,
            ]
            for _c in _uais_candidates:
                if _c and _c.exists():
                    sys.path.insert(0, str(_c.parent))
                    break

            try:
                import uais
                os.environ.setdefault("OLLAMA_HOST", d.get("ollama_host",
                                                            "http://127.0.0.1:11434"))
                hw    = uais.probe_hardware()
                prov  = uais.build_provider_chain(hw)
                model = d["model"] or hw.model

                # Build restricted cfg: capability filtering enforced in
                # _dispatch via the SkillRunner whitelist
                cfg   = uais.AgentConfig(
                    provider=prov, model=model, workspace=ws,
                    use_tools=True, autonomy_level=2)
                soul  = uais.load_ws_file(ws, "SOUL.md", uais._DEFAULT_SOUL)
                mem   = uais.Memory(ws)
                agent = uais.Agent(cfg, soul=soul, memory=mem, hw=hw)

                # Monkey-patch _dispatch to enforce capability list
                _orig_dispatch = agent._dispatch
                def _restricted_dispatch(name, args, log=None):
                    if name not in caps:
                        return (f"[SKILL_BLOCKED: tool '{name}' not in "
                                f"declared capabilities {sorted(caps)}]")
                    return _orig_dispatch(name, args, log=log)
                agent._dispatch = _restricted_dispatch

                skill_sys = (
                    "You are executing a UAIS skill. Follow these instructions "
                    "exactly:\
\
" + d["skill_md"]
                )
                agent.soul = skill_sys
                result = agent.run_task(d["task"], log=lambda *_: None)
                print(json.dumps({"ok": True, "result": result}))
            except Exception as _e:
                print(json.dumps({"ok": False, "error": str(_e)}))
        """).strip()
        try:
            r = subprocess.run(
                [sys.executable, "-c", runner_code, payload],
                capture_output=True, text=True, timeout=120,
            )
            output = (r.stdout + r.stderr).strip()
            if not output:
                return f"[SkillRunner] completed (caps={allowed})"
            # Try to parse JSON result
            try:
                parsed = json.loads(output.splitlines()[-1])
                if parsed.get("ok"):
                    return str(parsed.get("result", ""))
                return f"[SkillRunner error] {parsed.get('error', output)}"
            except (json.JSONDecodeError, IndexError):
                return output
        except subprocess.TimeoutExpired:
            return "[SkillRunner] Skill timed out after 120s"
        except Exception as e:
            return f"[SkillRunner error: {e}]"


# ══════════════════════════════════════════════════════════════════════════════
# §6  WORKSPACE  (workspace-compatible file structure)
# ══════════════════════════════════════════════════════════════════════════════
# Full file roster matches UAIS's workspace kernel:
#   SOUL.md       — agent identity, personality, values (who the agent IS)
#   HEARTBEAT.md  — recurring task instructions (what it watches for)
#   AGENTS.md     — agent roster, routing rules, trust levels
#   IDENTITY.md   — user identity, preferences, context
#   TOOLS.md      — tool whitelist + domain policies (feeds CriticGate constraints)
#   MEMORY.md     — distilled long-term memory (human-readable)
#   skills/       — skill-compatible SKILL.md directories
#   sessions/     — JSONL session transcripts (append-only per UAIS pattern)
#   memory/       — structured memory (JSON + optional ChromaDB)
#   logs/         — heartbeat + tool execution logs

def _workspace_root() -> Path:
    """Canonical workspace path.
    Override order: UAIS_WORKSPACE env var > platform default.
    Platform defaults: Windows → %APPDATA%/UAIS, others → ~/.uais
    """
    if env := os.environ.get("UAIS_WORKSPACE", ""):
        return Path(env)
    if platform.system() == "Windows":
        return Path(os.environ.get("APPDATA",
                    str(Path.home() / "AppData" / "Roaming"))) / "UAIS"
    return Path.home() / ".uais"


def load_ws_file(workspace: Path, filename: str,
                 default: str = "") -> str:
    p = workspace / filename
    try:
        return p.read_text(encoding="utf-8") if p.exists() else default
    except Exception:
        return default


